import psycopg2
import re


ALLOWED_EXTENSIONS = {
    'plpythonu',
    'plpgsql',
    'pgcrypto',
    'uuid-ossp',
    'hstore',
    'pg_trgm',
    'btree_gist',
    'btree_gin',
    'citext',
    'ltree',
    'tablefunc',
    'fuzzystrmatch',
    'unaccent',
    'postgis',
    'postgis_topology',
    'pg_stat_statements',
    'dblink',
    'file_fdw',
    'postgres_fdw',
    'intarray',
    'earthdistance',
    'cube',
}

VALID_EXTENSION_NAME_PATTERN = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_\-]*$')


def validate_extension_name(extension_name):
    """Validate that the extension name is safe and allowed."""
    if not extension_name:
        raise ValueError("Extension name cannot be empty.")

    extension_name = extension_name.strip().lower()

    if not VALID_EXTENSION_NAME_PATTERN.match(extension_name):
        raise ValueError(
            f"Invalid extension name format: '{extension_name}'. "
            "Extension names must start with a letter or underscore and contain "
            "only letters, digits, underscores, or hyphens."
        )

    if extension_name not in ALLOWED_EXTENSIONS:
        raise ValueError(
            f"Extension '{extension_name}' is not in the allowed extensions list. "
            f"Allowed extensions: {', '.join(sorted(ALLOWED_EXTENSIONS))}"
        )

    return extension_name


def get_db_connection(host, port, dbname, user, password):
    """Create and return a database connection."""
    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password
    )
    conn.autocommit = True
    return conn


def install_extension(conn, extension_name):
    """Safely install a PostgreSQL extension using a whitelist approach."""
    validated_name = validate_extension_name(extension_name)

    # Use psycopg2's sql module for safe identifier quoting
    from psycopg2 import sql

    query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
        sql.Identifier(validated_name)
    )

    cursor = conn.cursor()
    try:
        cursor.execute(query)
        print(f"Extension '{validated_name}' installed successfully.")
        return True
    except psycopg2.Error as e:
        print(f"Error installing extension '{validated_name}': {e}")
        return False
    finally:
        cursor.close()


def list_installed_extensions(conn):
    """List all currently installed extensions."""
    cursor = conn.cursor()
    try:
        cursor.execute("SELECT extname, extversion FROM pg_extension ORDER BY extname;")
        extensions = cursor.fetchall()
        print("\nInstalled extensions:")
        print("-" * 40)
        for ext_name, ext_version in extensions:
            print(f"  {ext_name} (version: {ext_version})")
        print("-" * 40)
        return extensions
    except psycopg2.Error as e:
        print(f"Error listing extensions: {e}")
        return []
    finally:
        cursor.close()


def uninstall_extension(conn, extension_name):
    """Safely uninstall a PostgreSQL extension."""
    validated_name = validate_extension_name(extension_name)

    from psycopg2 import sql

    query = sql.SQL("DROP EXTENSION IF EXISTS {}").format(
        sql.Identifier(validated_name)
    )

    cursor = conn.cursor()
    try:
        cursor.execute(query)
        print(f"Extension '{validated_name}' uninstalled successfully.")
        return True
    except psycopg2.Error as e:
        print(f"Error uninstalling extension '{validated_name}': {e}")
        return False
    finally:
        cursor.close()


